// TG-138: Aggregate this week's metrics
const supabaseUrl = 'https://lwtmvzhwekgdxkaisfra.supabase.co/rest/v1';
const supabaseKey = 'sb_publishable_DeX21ldoDKl3NyJeFZzR1w_eWBUkx-v';
const supabaseHeaders = {
  'apikey': supabaseKey,
  'Authorization': `Bearer ${supabaseKey}`
};

const now = new Date();
const weekAgo = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000).toISOString();

// 1. Leads this week
let leads = [];
try {
  leads = await this.helpers.httpRequest({
    method: 'GET',
    url: `${supabaseUrl}/leads?created_at=gte.${weekAgo}&select=id,name,source,status,created_at`,
    headers: supabaseHeaders
  });
} catch (e) { leads = []; }

// 2. Jobs this week from jobber_email_events
let jobs = [];
try {
  jobs = await this.helpers.httpRequest({
    method: 'GET',
    url: `${supabaseUrl}/jobber_email_events?event_date=gte.${weekAgo}&select=id,event_type,client_name`,
    headers: supabaseHeaders
  });
} catch (e) { jobs = []; }

// 3. Google reviews this week
let reviews = [];
try {
  reviews = await this.helpers.httpRequest({
    method: 'GET',
    url: `${supabaseUrl}/google_reviews?created_at=gte.${weekAgo}&select=id,author_name,rating,text`,
    headers: supabaseHeaders
  });
} catch (e) { reviews = []; }

// 4. Blog posts published this week
let blogPosts = [];
try {
  blogPosts = await this.helpers.httpRequest({
    method: 'GET',
    url: `${supabaseUrl}/blog_posts?published_at=gte.${weekAgo}&status=eq.published&select=id,title,slug`,
    headers: supabaseHeaders
  });
} catch (e) { blogPosts = []; }

// 5. GBP posts this week
let gbpPosts = [];
try {
  gbpPosts = await this.helpers.httpRequest({
    method: 'GET',
    url: `${supabaseUrl}/gbp_posts?published_at=gte.${weekAgo}&select=id,post_type,topic`,
    headers: supabaseHeaders
  });
} catch (e) { gbpPosts = []; }

// 6. Social posts this week
let socialPosts = [];
try {
  socialPosts = await this.helpers.httpRequest({
    method: 'GET',
    url: `${supabaseUrl}/social_posts?published_at=gte.${weekAgo}&status=eq.published&select=id,platforms,pillar`,
    headers: supabaseHeaders
  });
} catch (e) { socialPosts = []; }

// 7. n8n executions this week
let executions = { total: 0, errors: 0 };
try {
  const allExecs = await this.helpers.httpRequest({
    method: 'GET',
    url: 'https://tgyardcare.app.n8n.cloud/api/v1/executions?limit=100',
    headers: { 'X-N8N-API-KEY': 'N8N_API_KEY_PLACEHOLDER' }
  });
  const data = allExecs.data || allExecs || [];
  const weekData = Array.isArray(data) ? data.filter(e => new Date(e.startedAt) >= new Date(weekAgo)) : [];
  executions.total = weekData.length;
  executions.errors = weekData.filter(e => e.status === 'error' || e.finished === false).length;
} catch (e) { /* defaults */ }

return [{
  json: {
    leads: Array.isArray(leads) ? leads : [],
    jobs: Array.isArray(jobs) ? jobs : [],
    reviews: Array.isArray(reviews) ? reviews : [],
    blogPosts: Array.isArray(blogPosts) ? blogPosts : [],
    gbpPosts: Array.isArray(gbpPosts) ? gbpPosts : [],
    socialPosts: Array.isArray(socialPosts) ? socialPosts : [],
    executions,
    weekAgo
  }
}];

// TG-138: Fetch previous week's metrics and calculate trends
const supabaseUrl = 'https://lwtmvzhwekgdxkaisfra.supabase.co/rest/v1';
const supabaseKey = 'sb_publishable_DeX21ldoDKl3NyJeFZzR1w_eWBUkx-v';
const supabaseHeaders = {
  'apikey': supabaseKey,
  'Authorization': `Bearer ${supabaseKey}`
};

const current = $input.first().json;
const now = new Date();
const weekAgo = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000).toISOString();
const twoWeeksAgo = new Date(now.getTime() - 14 * 24 * 60 * 60 * 1000).toISOString();

// Previous week counts
let prevLeads = 0;
try {
  const r = await this.helpers.httpRequest({
    method: 'GET',
    url: `${supabaseUrl}/leads?created_at=gte.${twoWeeksAgo}&created_at=lt.${weekAgo}&select=id`,
    headers: supabaseHeaders
  });
  prevLeads = Array.isArray(r) ? r.length : 0;
} catch (e) { prevLeads = 0; }

let prevJobs = 0;
try {
  const r = await this.helpers.httpRequest({
    method: 'GET',
    url: `${supabaseUrl}/jobber_email_events?event_date=gte.${twoWeeksAgo}&event_date=lt.${weekAgo}&select=id`,
    headers: supabaseHeaders
  });
  prevJobs = Array.isArray(r) ? r.length : 0;
} catch (e) { prevJobs = 0; }

let prevReviews = 0;
try {
  const r = await this.helpers.httpRequest({
    method: 'GET',
    url: `${supabaseUrl}/google_reviews?created_at=gte.${twoWeeksAgo}&created_at=lt.${weekAgo}&select=id`,
    headers: supabaseHeaders
  });
  prevReviews = Array.isArray(r) ? r.length : 0;
} catch (e) { prevReviews = 0; }

let prevBlogPosts = 0;
try {
  const r = await this.helpers.httpRequest({
    method: 'GET',
    url: `${supabaseUrl}/blog_posts?published_at=gte.${twoWeeksAgo}&published_at=lt.${weekAgo}&status=eq.published&select=id`,
    headers: supabaseHeaders
  });
  prevBlogPosts = Array.isArray(r) ? r.length : 0;
} catch (e) { prevBlogPosts = 0; }

function pctChange(current, previous) {
  if (previous === 0) return current > 0 ? '+100%' : '0%';
  const change = ((current - previous) / previous * 100).toFixed(0);
  return change > 0 ? `+${change}%` : `${change}%`;
}

return [{
  json: {
    ...current,
    trends: {
      leads: pctChange(current.leads.length, prevLeads),
      jobs: pctChange(current.jobs.length, prevJobs),
      reviews: pctChange(current.reviews.length, prevReviews),
      blogPosts: pctChange(current.blogPosts.length, prevBlogPosts)
    },
    prev: {
      leads: prevLeads,
      jobs: prevJobs,
      reviews: prevReviews,
      blogPosts: prevBlogPosts
    }
  }
}];

// TG-138: Build formatted weekly report for Telegram
const d = $input.first().json;

const now = new Date();
const weekStart = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000)
  .toLocaleDateString('en-US', { timeZone: 'America/Chicago', month: 'short', day: 'numeric' });
const weekEnd = now.toLocaleDateString('en-US', { timeZone: 'America/Chicago', month: 'short', day: 'numeric', year: 'numeric' });

const leads = d.leads || [];
const jobs = d.jobs || [];
const reviews = d.reviews || [];
const blogPosts = d.blogPosts || [];
const gbpPosts = d.gbpPosts || [];
const socialPosts = d.socialPosts || [];
const executions = d.executions || { total: 0, errors: 0 };
const trends = d.trends || {};
const prev = d.prev || {};

// Lead sources breakdown
const leadSources = {};
for (const l of leads) {
  const src = l.source || 'unknown';
  leadSources[src] = (leadSources[src] || 0) + 1;
}
let sourceLines = Object.entries(leadSources)
  .map(([src, count]) => `  \u2022 ${src}: ${count}`).join('\n') || '  None';

// Review avg rating
let avgRating = 0;
if (reviews.length > 0) {
  avgRating = (reviews.reduce((sum, r) => sum + (r.rating || 0), 0) / reviews.length).toFixed(1);
}

// Social breakdown by pillar
const pillarCounts = {};
for (const p of socialPosts) {
  const pillar = p.pillar || 'other';
  pillarCounts[pillar] = (pillarCounts[pillar] || 0) + 1;
}
let pillarLines = Object.entries(pillarCounts)
  .map(([p, c]) => `  \u2022 ${p}: ${c}`).join('\n') || '  None';

// System health
const successRate = executions.total > 0
  ? ((1 - executions.errors / executions.total) * 100).toFixed(1)
  : '100.0';

const lines = [
  `\ud83d\udcca TOTALGUARD WEEKLY REPORT`,
  `${weekStart} \u2014 ${weekEnd}`,
  '',
  `\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501`,
  '',
  `\ud83d\udce5 LEADS`,
  `New: ${leads.length} (${trends.leads || '0%'} vs last week)`,
  `Previous week: ${prev.leads || 0}`,
  sourceLines,
  '',
  `\ud83d\udee0\ufe0f OPERATIONS`,
  `Jobs: ${jobs.length} (${trends.jobs || '0%'} vs last week)`,
  `Previous week: ${prev.jobs || 0}`,
  '',
  `\u2b50 REPUTATION`,
  `Reviews: ${reviews.length} (${trends.reviews || '0%'} vs last week)`,
  reviews.length > 0 ? `Avg rating: ${avgRating}/5` : '',
  '',
  `\ud83d\udcdd CONTENT`,
  `Blog posts: ${blogPosts.length} (${trends.blogPosts || '0%'} vs last week)`,
  `GBP posts: ${gbpPosts.length}`,
  `Social posts: ${socialPosts.length}`,
  pillarLines,
  '',
  `\u2699\ufe0f SYSTEM HEALTH`,
  `Executions: ${executions.total}`,
  `Errors: ${executions.errors}`,
  `Success rate: ${successRate}%`,
  '',
  `\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501`,
  '',
  `\ud83c\udfc6 TOP WIN: ${leads.length > (prev.leads || 0) ? `Lead volume up ${trends.leads}` : reviews.length > 0 ? `${reviews.length} new reviews` : 'Steady operations'}`,
  '',
  `\u26a0\ufe0f TOP ISSUE: ${executions.errors > 5 ? `${executions.errors} workflow errors need attention` : leads.length === 0 ? 'Zero new leads this week' : 'All systems nominal'}`,
  '',
  `Have a great week! \ud83d\ude80`
];

return [{ json: { message: lines.filter(l => l !== undefined).join('\n') } }];
